      "keystrokes": "cat > /app/gather_info.py <<'PY'
import urllib.request, json, re, time, os, sys

def fetch(url, timeout=10, headers=None):
    h={'User-Agent':'Mozilla/5.0'}
    if headers:
        h.update(headers)
    req=urllib.request.Request(url, headers=h)
    with urllib.request.urlopen(req, timeout=timeout) as r:
        return r.read()

# DHFR from plasmid
text=open('/app/plasmid.gb').read()
m=re.search(r'/translation="([^"]+)"', text, re.S)
dhfr=m.group(1).replace('\n','').replace(' ','') if m else ''
print('DHFR_LEN', len(dhfr), 'DHFR_SEQ', dhfr)
open('/app/dhfr_protein.txt','w').write(dhfr)

ids=[x.strip() for x in open('/app/pdb_ids.txt') if x.strip()]
print('PDB_IDS', len(ids), ids)

cache={}
meta={}
for pid in ids:
    # FASTA
    fas=[]
    try:
        data=fetch(f'https://www.rcsb.org/fasta/entry/{pid}/download').decode('utf-8','replace')
        cur=None
        for line in data.splitlines():
            if line.startswith('>'):
                cur={'header':line[1:], 'seq':''}
                fas.append(cur)
            elif cur is not None:
                cur['seq']+=line.strip()
    except Exception as e:
        fas=[{'header':f'ERROR {type(e).__name__}: {e}', 'seq':''}]
    cache[pid]=fas
    # PDBe summary
    try:
        d=json.loads(fetch(f'https://www.ebi.ac.uk/pdbe/api/pdb/entry/summary/{pid.lower()}'))
        entry=d[pid.lower()][0]
        title=entry.get('title','')
        comps=[]
        for mm in entry.get('molecules',[]):
            comps.append(mm.get('molecule_name',''))
            if 'synonym' in mm:
                comps.append('syn:'+str(mm['synonym']))
        meta[pid]={'title':title,'molecules':comps}
    except Exception as e:
        meta[pid]={'error':f'{type(e).__name__}: {e}'}
    h=fas[0]['header'] if fas else ''
    s=fas[0]['seq'][:60] if fas else ''
    print('PDB', pid, 'title', meta[pid].get('title',''), 'mols', meta[pid].get('molecules',[])[:3], 'chains', len(fas), 'hdr', h, 'seqlen', len(fas[0]['seq']) if fas else 0, 'seq', s)
    time.sleep(0.05)

open('/app/pdb_cache.json','w').write(json.dumps(cache,indent=1))
open('/app/pdb_meta.json','w').write(json.dumps(meta,indent=1))
print('Saved /app/pdb_cache.json and /app/pdb_meta.json')

# FPbase: fetch protein list and basic spectra
fp=[]
try:
    raw=fetch('https://www.fpbase.org/api/4.0/proteins/?format=json')
    fp=json.loads(raw)
    open('/app/fpbase_proteins.json','w').write(json.dumps(fp,indent=1))
    print('FPbase count', len(fp) if isinstance(fp, list) else 'not-list')
    # Print proteins likely matching PDB ids or relevant names
    for p in (fp if isinstance(fp, list) else []):
        print('FPBASE', p)
except Exception as e:
    print('FPbase list error', type(e).__name__, e)
    # try search endpoint variants
    for q in ['505','610','mCherry','mRuby','mNeonGreen','EGFP','sfGFP','TagRFP','mOrange']:
        try:
            raw=fetch(f'https://www.fpbase.org/api/4.0/proteins/?search={q}&format=json')
            d=json.loads(raw)
            print('FPBASE_SEARCH', q, type(d).__name__, len(d) if isinstance(d,list) else d)
        except Exception as e2:
            print('FPbase search error', q, type(e2).__name__, e2)
